SELECT COUNT(DISTINCT S.PK_SIAPE) AS QTD FROM SERVIDOR S JOIN CARGO C ON C.FK_SIAPE = S.PK_SIAPE WHERE LOWER(S.GENERO) = LOWER('masculino') AND (LOWER(C.FUNCAO) LIKE LOWER('%substit%') OR LOWER(C.ATIVIDADE) LIKE LOWER('%substit%')) AND LOWER(C.SIGLA_CAMPUS) = LOWER('gyn') AND C.DATA_ENTRADA <= DATE('now') AND (C.DATA_SAIDA IS NULL OR C.DATA_SAIDA >= DATE('now', '-5 years')) AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%matem%') OR LOWER(S.AREA_INGRESSO_OG) LIKE LOWER('%matem%'))